    }
    
    func log(_ message: String, level: LogLevel = .info, type: SecureLogType? = nil) {
        guard shouldLog(level) else { return }
        
        let timestamp = Date().formatted(date: .abbreviated, time: .shortened)
        let logLevel = level.description.uppercased()
        let logType = type?.description ?? "DEFAULT"
        
        let logMessage = "[\(timestamp)] [\(logLevel)] [\(logType)] \(message)"
        
        switch level {
        case .debug:
            print(logMessage)
        case .info:
            print(logMessage)
        case .warning:
            print(logMessage)
        case .error:
            print(logMessage)
        }
    }
    
