    private func redactSensitiveFields(_ payload: [String: Any]?) -> String {
        guard let payload = payload else { return "N/A" }
        
        var redacted = payload
        
        let sensitiveKeys = ["password", "token", "secret", "auth", "credential", "key", "access_token", "refresh_token"]
        
