extension String {
    func redacted() -> String {
        if self.isEmpty { return "N/A" }
        return self.count > 10 ? "\(String(self.prefix(5)))...\(String(self.suffix(5)))" : "[REDACTED]"
    }
}

extension LogLevel: CustomStringConvertible {
    var description: String {
        switch self {
        case .debug: return "DEBUG"
        case .info: return "INFO"
        case .warning: return "WARNING"
        case .error: return "ERROR"
        }
    }
}

extension SecureLogType: CustomStringConvertible {
    var description: String {
        switch self {
        case .authentication: return "AUTH"
        case .apiCall: return "API"
        case .userData: return "USER_DATA"
        case .error: return "ERROR"
        }
    }
